#!/usr/bin/env python3
import http.server, socketserver, os, json
from urllib.parse import urlparse

PORT    = int(os.environ.get('PORT', 8765))
LANDING = bytes.fromhex('').decode('utf-8')
HTML    = bytes.fromhex('').decode('utf-8')

class H(http.server.BaseHTTPRequestHandler):
    def do_GET(self):
        path = urlparse(self.path).path.rstrip('/')
        if   path == '/health': self._json(b'{"status":"ok"}')
        elif path == '/app':    self._html(HTML,    'no-cache')
        else:                   self._html(LANDING, 'public, max-age=3600')
    def do_POST(self):
        if self.path == '/export': self._e()
        else: self.send_response(200);self._c();self.end_headers();self.wfile.write(b'ok')
    def do_OPTIONS(self): self.send_response(200);self._c();self.end_headers()
    def _c(self):
        self.send_header('Access-Control-Allow-Origin','*')
        self.send_header('Access-Control-Allow-Methods','GET,POST,OPTIONS')
        self.send_header('Access-Control-Allow-Headers','Content-Type')
    def _json(self,b): self.send_response(200);self.send_header('Content-Type','application/json');self._c();self.end_headers();self.wfile.write(b)
    def _html(self,body,cache):
        self.send_response(200);self.send_header('Content-type','text/html; charset=utf-8')
        self.send_header('Cache-Control',cache);self._c();self.end_headers();self.wfile.write(body.encode('utf-8'))
    def _e(self):
        try:
            l=int(self.headers.get('Content-Length',0));body=self.rfile.read(l)
            p=json.loads(body);c=p.get('content','');fname=p.get('filename','export.csv')
            self.send_response(200);self.send_header('Content-Type','text/csv; charset=utf-8-sig')
            self.send_header('Content-Disposition',f'attachment; filename="{fname}"');self._c();self.end_headers()
            self.wfile.write(c.encode('utf-8-sig'))
        except Exception as e: self.send_response(500);self._c();self.end_headers();self.wfile.write(str(e).encode())
    def log_message(self,f,*a): pass

def main():
    socketserver.TCPServer.allow_reuse_address = True
    with socketserver.TCPServer(('0.0.0.0',PORT),H) as h:
        print(f'Leadger running on port {PORT}');h.serve_forever()

if __name__ == '__main__': main()
